import{_ as t,o as i,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"10. Best Practice Employment Commitment","description":"","frontmatter":{"title":"10. Best Practice Employment Commitment","eba":"Health Allied & Managers Admin 2021-2025","topics":["preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/preliminary/10-best-practice-employment-commitment.md","filePath":"ebas/has-managers-admin/common-terms/preliminary/10-best-practice-employment-commitment.md"}'),n={name:"ebas/has-managers-admin/common-terms/preliminary/10-best-practice-employment-commitment.md"};function a(m,e,s,p,c,l){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_10-best-practice-employment-commitment" tabindex="-1">10. Best Practice Employment Commitment <a class="header-anchor" href="#_10-best-practice-employment-commitment" aria-label="Permalink to &quot;10. Best Practice Employment Commitment&quot;">​</a></h1><p><strong>10.1</strong> The parties agree to establish a committee to discuss Best Practice Employment Commitments (BPEC) during the life of the Agreement on matters which include:</p><p><strong>(a)</strong> monitoring the implementation of the Agreement;</p><p><strong>(b)</strong> monitoring the achievement of employment diversity targets in-line with the DH Aboriginal Employment Strategy 2016-2021 and DH Disability Employment Strategy 2016-2021 (or their successors);</p><p><strong>(c)</strong> monitoring Workforce Mobility, Skills and Capability Development across the Victorian Public Health Sector, including the implementation of Workplace Trainer/Careers Advisors and associated initiatives;</p><p><strong>(d)</strong> developing an agreed framework which facilitates the Continuous Improvement of the Management &amp; Administrative Workers classifications, involving:</p><p><strong>(i)</strong> a review of the existing classification descriptors to identify opportunities for improvement, to be completed within 6 months of the commencement of the Agreement;</p><p><strong>(ii)</strong> development of trial descriptors to address the opportunities for improvement to be completed by 1 October 2022;</p><p><strong>(iii)</strong> descriptors to be trialled locally at volunteer Health Services in small cohorts, (not as enforceable terms) from 1 January 2023 for twelve months; and</p><p><strong>(iv)</strong> Health Service feedback regarding the suitability of the ‘trial descriptors’ to be reported to the BPEC in 2023 in order to inform bargaining preparation for 2024.</p><p><strong>10.2</strong> The Committee will schedule a minimum of six meetings per year.</p><p><strong>10.3</strong> The Committee will comprise nominated representatives from the union, the VHIA and DH (as required). The Committee may, by agreement, establish subgroups or delegate individual matters to a relevant health service(s) as required.</p><p><strong>10.4</strong> The Committee members may agree to engage a mediator to facilitate the resolution of disputes where the parties are unable to reach an agreement on the matters provided for in clause 10.1.</p>',13)])])}const h=t(n,[["render",a]]);export{g as __pageData,h as default};
